    BookmarkToTagRelationShip = Bookmark.tags.through
    BookmarkAsset = apps.get_model("bookmarks", "BookmarkAsset")

    # 第 1 步：强制补全所有空缺的 url_normalized，暴露所有潜在的重复项
    empty_bookmarks = Bookmark.objects.filter(url_normalized="")
    empty_count = empty_bookmarks.count()
    if empty_count > 0:
        logger.info(f"Step 1: Normalizing {empty_count} bookmarks with empty url_normalized...")
        for bookmark in empty_bookmarks.iterator(chunk_size=500):
            try:
                bookmark.url_normalized = normalize_url(bookmark.url)
                bookmark.save(update_fields=["url_normalized"])
            except Exception as e:
                logger.error(f"Error normalizing URL for bookmark {bookmark.id}: {e}")

    # 第 2 步：此时库中不再有空的 url_normalized，进行全局去重
    duplicates = (
        Bookmark.objects.values("owner", "url_normalized")
        .annotate(count=models.Count("id"))
        .filter(count__gt=1)
    )

    total_groups = duplicates.count()
    processed = 0
    if total_groups > 0:
        logger.info(f"Step 2: Found {total_groups} duplicate groups globally.")
        for dup in duplicates:
            try:
                with transaction.atomic():
                    bookmarks = list(
                        Bookmark.objects.filter(
                            owner=dup["owner"],
                            url_normalized=dup["url_normalized"],
                        ).order_by("-date_modified")
                    )
                    if len(bookmarks) > 1:
                        _merge_bookmark_group(
                            bookmarks[0], bookmarks[1:], BookmarkToTagRelationShip, BookmarkAsset
                        )
                        processed += 1
                        if processed % 100 == 0:
                            logger.info(f"Step 2: {processed}/{total_groups} groups processed...")
            except Exception as e:
                logger.error(f"Error deduplicating (owner={dup['owner']}, url_normalized={dup['url_normalized']}): {e}")
                continue
        logger.info(f"Deduplication complete. Merged {processed} groups.")


