    try:
        dst_conn.executescript(dump_sql)
        dst_conn.execute(SQL_CREATE_INDEX)
        dst_conn.commit()
    finally:
        dst_conn.close()

    # 3. 替换：原文件重命名为备份，新文件移到原位置
